function rotateLeft(a, k) {
  // your code here
}

solution:
function rotateLeft(a, k) {
  const n = a.length;
  if (n === 0) return [];
  k %= n;
  const out = [];
  for (let i = 0; i < n; i++) out.push(a[(i + k) % n]);
  return out;
}

tests:
if (JSON.stringify(rotateLeft([1, 2, 3, 4, 5], 2)) !== JSON.stringify([3, 4, 5, 1, 2])) throw new Error('two');
if (JSON.stringify(rotateLeft([1, 2, 3], 0)) !== JSON.stringify([1, 2, 3])) throw new Error('zero');
if (JSON.stringify(rotateLeft([1, 2, 3], 4)) !== JSON.stringify([2, 3, 1])) throw new Error('wrap');
if (JSON.stringify(rotateLeft([], 3)) !== JSON.stringify([])) throw new Error('empty');

